const input = $input.first().json;
const props = input.properties || {};

function textOf(property) {
  if (!property) return '';
  if (Array.isArray(property.title)) return property.title.map((item) => item.plain_text || '').join('').trim();
  if (Array.isArray(property.rich_text)) return property.rich_text.map((item) => item.plain_text || '').join('').trim();
  if (property.email) return property.email;
  if (property.phone_number) return property.phone_number;
  if (property.url) return property.url;
  if (property.select?.name) return property.select.name;
  if (property.status?.name) return property.status.name;
  if (Array.isArray(property.multi_select)) return property.multi_select.map((item) => item.name).filter(Boolean).join(', ');
  if (typeof property.number === 'number') return String(property.number);
  if (typeof property.checkbox === 'boolean') return property.checkbox ? 'true' : 'false';
  return '';
}

function safeDate(value) {
  if (!value) return null;
  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? null : date;
}

const leadName = textOf(props.Name) || textOf(props['Lead Name']) || 'there';
const firstName = (leadName.split(/\s+/)[0] || 'there').trim() || 'there';
const email = textOf(props.Email);
const phone = textOf(props.Phone);
const company = textOf(props.Company) || textOf(props['Company Name']) || textOf(props.Organization);
const industry = textOf(props.Industry);
const source = textOf(props.Source) || textOf(props['Lead Source']);
const role = textOf(props.Role) || textOf(props.Title) || textOf(props.Position);
const smsOptIn = Boolean(props['SMS Opt In']?.checkbox);
const optedOut = Boolean(props['Opted Out']?.checkbox);
const replied = Boolean(props.Replied?.checkbox);
const lastContactedRaw = props['Last Contacted']?.date?.start || props['Last Contacted']?.date?.end || input.last_contacted || input.lastContacted || null;
const lastContactedDate = safeDate(lastContactedRaw);
const daysSinceLastContact = lastContactedDate ? Math.max(0, Math.floor((Date.now() - lastContactedDate.getTime()) / 86400000)) : null;

const stageNumber = Number(props['Recovery Stage']?.number || 0);
const recoveryPhase = 'stage_1';

let leadScore = 40;
if (email) leadScore += 15;
if (phone) leadScore += 10;
if (smsOptIn && phone) leadScore += 20;
if (firstName !== 'there') leadScore += 5;
if (company) leadScore += 5;
if (industry) leadScore += 3;
if (source) leadScore += 3;
if (role) leadScore += 2;
if (daysSinceLastContact !== null) leadScore += Math.max(0, Math.min(12, 12 - Math.floor(daysSinceLastContact / 12)));
if (replied) leadScore += 5;
if (optedOut) leadScore = 0;
leadScore = Math.max(0, Math.min(100, leadScore));

const leadTier = leadScore >= 80 ? 'high' : leadScore >= 60 ? 'medium' : 'low';
const sendMode = smsOptIn && phone ? 'email_plus_sms' : 'email_only';
const recommendedTone = recoveryPhase === 'stage_1' ? 'curious and direct' : recoveryPhase === 'stage_2' ? 'value-led and specific' : 'calm, respectful, and final';
const openingLine = recoveryPhase === 'stage_1'
  ? `Hi ${firstName}, I noticed this went quiet and wanted to share one quick thought.`
  : recoveryPhase === 'stage_2'
    ? `Hi ${firstName}, I have one more idea that may make this worth revisiting.`
    : `Hi ${firstName}, I am going to close the loop on my side after this note.`;
const replyQuestion = recoveryPhase === 'stage_1'
  ? 'Is this still relevant right now?'
  : recoveryPhase === 'stage_2'
    ? 'Would it help if I sent a clearer example or next step?'
    : 'Should I close your file, or is there a better time to reconnect?';

const contextPieces = [company, role, industry, source].filter(Boolean);
const contextSummary = contextPieces.length ? contextPieces.join(' | ') : 'No extra CRM context available.';

const leadBrief = [
  `Lead name: ${leadName}`,
  `First name: ${firstName}`,
  `Email: ${email || 'missing'}`,
  `Phone: ${phone || 'missing'}`,
  `Score: ${leadScore}/100`,
  `Tier: ${leadTier}`,
  `Recovery phase: ${recoveryPhase}`,
  `Days since last contact: ${daysSinceLastContact === null ? 'unknown' : String(daysSinceLastContact)}`,
  `Send mode: ${sendMode}`,
  `Tone: ${recommendedTone}`,
  `Opening line: ${openingLine}`,
  `Reply question: ${replyQuestion}`,
  `CRM context: ${contextSummary}`
].join('\n');

return [{ json: {
  ...input,
  leadName,
  firstName,
  email,
  phone,
  company,
  industry,
  source,
  role,
  lastContacted: lastContactedRaw,
  daysSinceLastContact,
  smsOptIn,
  optedOut,
  replied,
  recoveryStage: stageNumber,
  recoveryPhase,
  leadScore,
  leadTier,
  sendMode,
  recommendedTone,
  openingLine,
  replyQuestion,
  leadBrief,
  leadContext: contextSummary,
} }];

